/**
 * Generate docs/cli.md from the bootstrap manifest plus the wizard-native
 * command list.
 *
 * Why bootstrap and not the generated TS: the generated file is gitignored
 * and only exists after a build. The bootstrap JSON is committed and
 * always present, so this script runs cleanly on a fresh clone too. When
 * the docs script is wired into CI or release builds, it should swap to
 * the generated manifest instead — the shape is identical.
 */

const fs = require('fs');
const path = require('path');

const REPO_ROOT = path.resolve(__dirname, '..');
const MANIFEST_PATH = path.join(REPO_ROOT, 'cli-manifest.bootstrap.json');
const OUT_PATH = path.join(REPO_ROOT, 'docs', 'cli.md');

// Wizard-native commands, hand-listed because they don't live in the
// context-mill manifest. Keep in sync with bin.ts when adding/removing
// a wizard-native command.
const NATIVE_COMMANDS = [
  {
    name: 'wizard',
    description:
      'The default integration. Detects the framework, authenticates, runs the agent, and walks the user through their first dashboard.',
  },
  {
    name: 'wizard mcp',
    description: 'Manage PostHog MCP servers across MCP-compatible clients.',
  },
  {
    name: 'wizard mcp add',
    description:
      'Install the PostHog MCP server in the user-selected MCP client(s).',
  },
  {
    name: 'wizard mcp remove',
    description: 'Remove the PostHog MCP server from MCP-compatible clients.',
  },
  {
    name: 'wizard mcp tutorial',
    description:
      'Walk the user through customizing the role-tailored prompts the MCP server installs.',
  },
  {
    name: 'wizard doctor',
    description:
      'Diagnose the PostHog setup for configuration issues, version mismatches, and missing prerequisites.',
  },
  {
    name: 'wizard audit web-analytics',
    description:
      'Audit and fix the PostHog web analytics setup. Wizard-native because it does more than run a single skill.',
  },
  {
    name: 'wizard source-maps',
    description:
      'Upload source maps for the PostHog error tracking integration. Framework-detected — runs the right uploader for the project.',
  },
  {
    name: 'wizard skill list',
    description:
      'List skills in the wizard catalog. Read-only — prints to stdout and exits.',
  },
  {
    name: 'wizard skill search <query>',
    description:
      'Search the catalog by name, description, or command path. Read-only.',
  },
  {
    name: 'wizard skill <id>',
    description:
      'Run any catalog skill by id, including ones not promoted as top-level commands.',
  },
];

function formatCommand(entry) {
  const path = entry.parentCommand
    ? `wizard ${entry.parentCommand} ${entry.command}`
    : `wizard ${entry.command}`;
  return `### \`${path}\`\n\n${entry.description}\n\n*Backed by context-mill skill: \`${entry.skillId}\`*`;
}

function generateMarkdown(manifest) {
  const lines = [];
  lines.push('# Wizard CLI reference');
  lines.push('');
  lines.push(
    `_Auto-generated by \`scripts/generate-cli-docs.cjs\` from manifest ` +
      `\`${manifest.buildVersion}\` (${manifest.buildTimestamp}). ` +
      `Don't hand-edit — regenerate with \`pnpm docs:cli\`._`,
  );
  lines.push('');
  lines.push(
    'The wizard\'s public command surface follows one rule: if the wizard can ' +
      'pick the variant for you (auto-detection), the command is flat. If you ' +
      'must pick, the command is a family. See ' +
      '[CONTRIBUTING.md](../CONTRIBUTING.md) for the full convention.',
  );
  lines.push('');

  const publicEntries = manifest.entries.filter((e) => e.surface === 'public');

  // Group by parentCommand
  const families = new Map();
  const flat = [];
  for (const entry of publicEntries) {
    if (entry.parentCommand) {
      const bucket = families.get(entry.parentCommand) ?? [];
      bucket.push(entry);
      families.set(entry.parentCommand, bucket);
    } else {
      flat.push(entry);
    }
  }

  lines.push('## Skill-backed commands');
  lines.push('');
  lines.push(
    'These come from context-mill. Adding a new one is a context-mill PR with a ' +
      '`cli:` block on the skill\'s `config.yaml` — no wizard release required.',
  );
  lines.push('');

  if (flat.length) {
    lines.push('### Flat commands');
    lines.push('');
    for (const entry of flat.sort((a, b) => a.command.localeCompare(b.command))) {
      lines.push(formatCommand(entry));
      lines.push('');
    }
  }

  for (const [parent, entries] of [...families.entries()].sort(([a], [b]) =>
    a.localeCompare(b),
  )) {
    lines.push(`### \`wizard ${parent}\` family`);
    lines.push('');
    lines.push(
      `\`wizard ${parent}\` with no subcommand opens an interactive picker over ` +
        `the children below. \`wizard ${parent} --help\` shows the same list as ` +
        'text.',
    );
    lines.push('');
    const sorted = entries.sort((a, b) => a.command.localeCompare(b.command));
    for (const entry of sorted) {
      lines.push(formatCommand(entry));
      lines.push('');
    }
  }

  lines.push('## Wizard-native commands');
  lines.push('');
  lines.push(
    'These live in the wizard repo itself, not in context-mill. They\'re ' +
      'hand-listed in `bin.ts` because they do more than dispatch a single skill ' +
      '(custom CI paths, sub-trees, post-install work, etc.).',
  );
  lines.push('');
  for (const cmd of NATIVE_COMMANDS) {
    lines.push(`### \`${cmd.name}\``);
    lines.push('');
    lines.push(cmd.description);
    lines.push('');
  }

  lines.push('## Internal flags');
  lines.push('');
  lines.push(
    'A handful of flags are accepted on every command but hidden from `--help`. ' +
      'They\'re for development, debugging, and test infrastructure. See ' +
      '[CONTRIBUTING.md](../CONTRIBUTING.md#internal-flags) for the catalog.',
  );
  lines.push('');

  return lines.join('\n');
}

function main() {
  const raw = fs.readFileSync(MANIFEST_PATH, 'utf8');
  const manifest = JSON.parse(raw);
  const markdown = generateMarkdown(manifest);
  fs.mkdirSync(path.dirname(OUT_PATH), { recursive: true });
  fs.writeFileSync(OUT_PATH, markdown);
  process.stdout.write(
    `[generate-cli-docs] wrote ${OUT_PATH} (${manifest.entries.filter((e) => e.surface === 'public').length} public entries, ${NATIVE_COMMANDS.length} native commands)\n`,
  );
}

main();
